import React, {type PropsWithChildren} from 'react'


import type {IFlexComponent} from "@lmb-it/kitsconcerto-types";
import {ResponsiveElement, useSeparator} from "../../factory";

const List =
    ({className, children, ref, ...props}: PropsWithChildren<IFlexComponent>) => {

        const {cssProps, nativeProps}  = useSeparator<any>(props)

        return (
            <ResponsiveElement ref={ref}
                               additionalClasses={className}
                               cssProps={cssProps}
                               nativeProps={nativeProps}
                               as={"List"}
                               children={children}/>
        )
    }


export default List;
